import LockOutlinedIcon from "@mui/icons-material/LockOutlined";
import { Dialog, DialogActions, DialogContent, DialogTitle, useMediaQuery } from "@mui/material";
import Avatar from "@mui/material/Avatar";
import Box from "@mui/material/Box";
import Button from "@mui/material/Button";
import Container from "@mui/material/Container";
import CssBaseline from "@mui/material/CssBaseline";
import TextField from "@mui/material/TextField";
import Typography from "@mui/material/Typography";
import { useTheme } from '@mui/material/styles';
import { debounce } from "@mui/material/utils";
import { navigate } from "gatsby";
import React, { useState } from "react";
import Layout from "../components/Layout";
import api from "../components/api";
import { CAPTCHA_KEY, validateCnpj, validateCpf, validateEmail } from "../utils/utils";
import ReCAPTCHA from "react-google-recaptcha";

export default function Login() {
    const recaptchaRef = React.useRef() as any;
    const theme = useTheme();
    const isLargeScreen = useMediaQuery(theme.breakpoints.up('lg'));

    const [value, setValue] = useState<string>("");

    const handleCheckLogin = async (): Promise<void> => {
        if (value.length < 3) {
            alert('Login inválido');
        } else {
            const onlyDigits = value.replace(/\D/g, '');
            let type = 'EMAIL';
            let formattedValue = value;
            if (onlyDigits.length === 11 && validateCpf(onlyDigits)) {
                type = 'CPF';
                formattedValue = onlyDigits;
            } else if (onlyDigits.length === 14 && validateCnpj(onlyDigits)) {
                type = 'CNPJ';
                formattedValue = onlyDigits;
            } else if (!validateEmail(formattedValue)) {
                alert('E-mail ou CPF inválido');
                return;
            }

            let token;
            if (recaptchaRef && recaptchaRef.current) {
                token = await recaptchaRef?.current.executeAsync();
            }
            if (!token) {
                alert("Verifique o reCAPTCHA");
            }
            else {
                api.post("/v1/request-login-code", {
                    captchaResponse: token,
                    type: type,
                    value: formattedValue
                })
                    .then((res) => {
                        if (res?.data?.registered) {
                            navigate('/verificar-codigo');
                        }
                        else {
                            navigate(`/checkout?type=${type}&value=${formattedValue}`)
                        }
                    }).catch((e) => {
                        setTimeout(() => recaptchaRef?.current?.reset(), 500);
                        if (e?.response?.status === 429) {
                            alert('Foram realizadas muitas tentativas de login, por favor, tente mais tarde.');
                        } else {
                            console.log(e);
                            alert('Houve um erro, tente mais tarde.');
                        }
                    });
            }

        }
    };


    return (
        <Layout hideFooter={true}>
            <ReCAPTCHA
                ref={recaptchaRef}
                size="invisible"
                sitekey={CAPTCHA_KEY}
            />
            <Container>
                <CssBaseline />
                <Box
                    sx={{
                        marginTop: 8,
                        display: "flex",
                        flexDirection: "column",
                        alignItems: "center",
                    }}
                >
                    <Avatar sx={{ m: 1, bgcolor: "secondary.main" }}>
                        <LockOutlinedIcon />
                    </Avatar>
                    <Typography component="h1" variant="h6">
                        Para finalizar a compra, informe seu E-mail ou CPF.
                    </Typography>
                    <Box width={isLargeScreen ? '50%' : '80%'}>
                        <TextField
                            margin="normal"
                            fullWidth
                            label="E-mail ou CPF"
                            name="email"
                            autoComplete="email"
                            onKeyUp={(e) => e.key === "Enter" && handleCheckLogin()}
                            onChange={(e) => setValue(e.target.value)}
                            autoFocus
                        />

                        <Button
                            fullWidth
                            variant="contained"
                            type="submit"
                            onClick={debounce(handleCheckLogin, 500)}
                            sx={{ mt: 3, mb: 2 }}
                        >
                            Continuar
                        </Button>

                    </Box>
                </Box>
            </Container>
        </Layout>
    );
}
